def setup_logging():
    """Initialize the logging configuration."""
    logging.config.dictConfig(LOGGING_CONFIG)
    logger = logging.getLogger("application")
    logger.info("Logging infrastructure initialized successfully.")
    return logger


def get_logger(name: str) -> logging.Logger:
    """
    Get a logger instance for the given module/component name.
    
    Args:
        name: The name of the module or component. Will be prefixed with 'application.'
              if not already.
    
    Returns:
        A configured logger instance.
    """
    if not name.startswith("application"):
        name = f"application.{name}"
    return logging.getLogger(name)


class LogContext:
    """Context manager that adds contextual information to log records."""

    def __init__(self, logger: logging.Logger, **kwargs):
        self.logger = logger
        self.context = kwargs
        self._old_factory = None

    def __enter__(self):
        old_factory = logging.getLogRecordFactory()
        self._old_factory = old_factory
        context = self.context

        def record_factory(*args, **kwargs):
            record = old_factory(*args, **kwargs)
            for key, value in context.items():
                setattr(record, key, value)
            # Append context to message
            context_str = " ".join(f"{k}={v}" for k, v in context.items())
            record.msg = f"{record.msg} [{context_str}]"
            return record

        logging.setLogRecordFactory(record_factory)
        return self.logger

    def __exit__(self, exc_type, exc_val, exc_tb):
        if self._old_factory:
            logging.setLogRecordFactory(self._old_factory)
        return False


class HealthCheckFilter(logging.Filter):
    """Filter out health check requests from access logs to reduce noise."""

    HEALTH_CHECK_PATHS = {"/health", "/healthz", "/ready", "/readiness", "/liveness"}

    def filter(self, record: logging.LogRecord) -> bool:
        message = record.getMessage()
        return not any(path in message for path in self.HEALTH_CHECK_PATHS)


class SensitiveDataFilter(logging.Filter):
    """Filter that redacts sensitive information from log messages."""

    SENSITIVE_PATTERNS = [
        "password",
        "secret",
        "token",
        "api_key",
        "apikey",
        "authorization",
        "credit_card",
        "ssn",
    ]

    def filter(self, record: logging.LogRecord) -> bool:
        message = record.getMessage().lower()
        for pattern in self.SENSITIVE_PATTERNS:
            if pattern in message:
                record.msg = self._redact_message(record.msg, pattern)
        return True

    @staticmethod
    def _redact_message(message: str, pattern: str) -> str:
        """Simple redaction - in production, use regex for more precise redaction."""
        import re
        # Redact values after common assignment patterns
        redacted = re.sub(
            rf'({pattern}\s*[=:]\s*)[^\s,;]+',
            rf'\1[REDACTED]',
            message,
            flags=re.IGNORECASE,
        )
        return redacted


def add_health_check_filter():
    """Add health check filter to access logger."""
    access_logger = logging.getLogger("application.access")
    access_logger.addFilter(HealthCheckFilter())


def add_sensitive_data_filter():
    """Add sensitive data filter to all application handlers."""
    app_logger = logging.getLogger("application")
    sensitive_filter = SensitiveDataFilter()
    for handler in app_logger.handlers:
        handler.addFilter(sensitive_filter)


